import { useParams, Link } from "react-router-dom";
import Card from "../components/Card";

export default function RoadmapPage() {
  const { name } = useParams();

  // ✅ fallback (sidebar support)
  const domainKey = (name || localStorage.getItem("selectedDomain") || "ai-and-ml").toLowerCase();

  // ✅ store domain
  if (name) {
    localStorage.setItem("selectedDomain", domainKey);
  }

  const timeline = localStorage.getItem("timeline") || "3 months";
  const totalDays = parseInt(timeline) * 30;

  const currentDay = parseInt(localStorage.getItem("currentDay") || "1");

  // 🔥 Topic structure (multiple topics per day)
  const topicMap = {
    "ai-and-ml": [
      ["Python Basics", "Variables"],
      ["Loops", "Conditions"],
      ["Functions"],
      ["NumPy"],
      ["Pandas"],
      ["Data Visualization"],
      ["Statistics"],
      ["ML Algorithms"],
      ["Model Evaluation"],
      ["Deep Learning"],
      ["Neural Networks"],
      ["Final Project"]
    ],

    "web-development": [
      ["HTML", "CSS"],
      ["Flexbox", "Grid"],
      ["JavaScript Basics"],
      ["DOM Manipulation"],
      ["ES6"],
      ["React Basics"],
      ["Hooks"],
      ["API Integration"],
      ["Node.js"],
      ["MongoDB"],
      ["Full Stack Project"]
    ]
  };

  const topics = topicMap[domainKey] || [["Learn fundamentals"]];

  // ✅ Get today's tasks
  const getTasksForDay = (day) => {
    const index = Math.floor((day / totalDays) * topics.length);
    const newTasks = topics[index] || [];

    // 🔥 carry forward unfinished tasks
    const carry = JSON.parse(localStorage.getItem("carryForward") || "[]");

    return [...carry, ...newTasks];
  };

  const todayTasks = getTasksForDay(currentDay);

  return (
    <div className="space-y-8">
      <Card
        title={`${domainKey.replace(/-/g, " ")} Roadmap`}
        description={`Day ${currentDay} of ${totalDays}`}
      >

        {/* Back */}
        <div className="mb-6">
          <Link to="/domains" className="text-blue-600 underline text-sm">
            ← Back to Domains
          </Link>
        </div>

        {/* Today Tasks */}
        <div className="space-y-3">
          <h3 className="text-lg font-semibold">
            📅 Today's Learning Plan
          </h3>

          {todayTasks.map((task, index) => (
            <div
              key={index}
              className="rounded-xl bg-green-100 dark:bg-slate-700 p-4"
            >
              {task}
            </div>
          ))}
        </div>

        {/* Go to Tasks */}
        <div className="mt-6">
          <Link to="/tasks">
            <button className="px-4 py-2 bg-teal-500 text-white rounded-lg">
              Go to Tasks
            </button>
          </Link>
        </div>

      </Card>
    </div>
  );
}
